messages.message:
Patch Set 2:

how about changing the patch "ldiskfs/kernel_patches/patches/rhel7/ext4-osd-iop-common.patch",
which introduces this function "ext4_add_dot_dotdot". and there is already an "ext4_mark_inode_dirty"
in the similar patch for RHEL6.x (ldiskfs/kernel_patches/patches/rhel6.3/ext4-osd-iop-common.patch)

diff --git a/ldiskfs/kernel_patches/patches/rhel7/ext4-data-in-dirent.patch b/ldiskfs/kernel_patches/patches/rhel7/ext4-data-in-dirent.patch
index 26b1e78..008f8f3 100644
--- a/ldiskfs/kernel_patches/patches/rhel7/ext4-data-in-dirent.patch
+++ b/ldiskfs/kernel_patches/patches/rhel7/ext4-data-in-dirent.patch
@@ -613,18 +613,18 @@ Index: linux-3.10.0-123.13.2.el7.x86_64/fs/ext4/namei.c
 +                      struct inode *inode,
 +                      const void *data1, const void *data2)
  {
-       if (IS_ERR(handle))
-               return PTR_ERR(handle);
-@@ -2518,7 +2608,7 @@ int ext4_add_dot_dotdot(handle_t *handle
+       int rc;
+
+@@ -2520,7 +2610,7 @@ int ext4_add_dot_dotdot(handle_t *handle

        inode->i_op = &ext4_dir_inode_operations;
        inode->i_fop = &ext4_dir_operations;
--      return ext4_init_new_dir(handle, dir, inode);
-+      return ext4_init_new_dir(handle, dir, inode, data1, data2);
- }
- EXPORT_SYMBOL(ext4_add_dot_dotdot);
- 
-@@ -2546,7 +2636,7 @@ retry:
+-      rc = ext4_init_new_dir(handle, dir, inode);
++      rc = ext4_init_new_dir(handle, dir, inode, data1, data2);
+       if (rc == 0)
+               rc = ext4_mark_inode_dirty(handle, inode);
+
+@@ -2552,7 +2642,7 @@ retry:

        inode->i_op = &ext4_dir_inode_operations;
        inode->i_fop = &ext4_dir_operations;
@@ -633,7 +633,7 @@ Index: linux-3.10.0-123.13.2.el7.x86_64/fs/ext4/namei.c
        if (err)
                goto out_clear_inode;
        err = ext4_mark_inode_dirty(handle, inode);
-@@ -2598,7 +2688,7 @@ static int empty_dir(struct inode *inode
+@@ -2604,7 +2694,7 @@ static int empty_dir(struct inode *inode
        }

        sb = inode->i_sb;
diff --git a/ldiskfs/kernel_patches/patches/rhel7/ext4-osd-iop-common.patch b/ldiskfs/kernel_patches/patches/rhel7/ext4-osd-iop-common.patch
index ddbe93d..5052e82 100644
--- a/ldiskfs/kernel_patches/patches/rhel7/ext4-osd-iop-common.patch
+++ b/ldiskfs/kernel_patches/patches/rhel7/ext4-osd-iop-common.patch
@@ -67,7 +67,7 @@ Index: linux-3.10.0-123.13.2.el7.x86_64/fs/ext4/namei.c
  /*
   * By the time this is called, we already have created
   * the directory cache entry for the new file, but it
-@@ -2402,6 +2426,23 @@ out:
+@@ -2402,6 +2426,29 @@ out:
        return err;
  }

@@ -76,6 +76,8 @@ Index: linux-3.10.0-123.13.2.el7.x86_64/fs/ext4/namei.c
 +int ext4_add_dot_dotdot(handle_t *handle, struct inode *dir,
 +                      struct inode *inode)
 +{
++      int rc;
++
 +      if (IS_ERR(handle))
 +
@@ -84,7 +86,11 @@ Index: linux-3.10.0-123.13.2.el7.x86_64/fs/ext4/namei.c
 +
 +      inode->i_op = &ext4_dir_inode_operations.ops;
 +      inode->i_fop = &ext4_dir_operations;
-+      return ext4_init_new_dir(handle, dir, inode);
++      rc = ext4_init_new_dir(handle, dir, inode);
++      if (rc == 0)
++              rc = ext4_mark_inode_dirty(handle, inode);
++
++      return rc;
 +}
 +EXPORT_SYMBOL(ext4_add_dot_dotdot);
 +
